// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IKarma {
    function getKarma(address user) external view returns (uint256);
    function award(address user, uint256 amount, string calldata reason) external;
    function slash(address user, uint256 amount, string calldata reason) external;
}

/// @title BucketLending
/// @notice Privacy-first, reputation-gated, gasless-friendly lending.
///
/// Design goals:
///   1. Borrow/repay/fund happen through stealth addresses so activity cannot be
///      trivially linked to a user's primary identity.
///   2. Loans are restricted to fixed "buckets" (e.g. 0.1, 0.5, 1 ETH) so amounts
///      alone do not fingerprint a user. Larger borrow requests are split client-side
///      into multiple independent loans against different stealth addresses.
///   3. Borrowing power is gated by Karma — a non-transferable reputation signal
///      from Status Network. No collateral is posted.
///   4. Defaults slash Karma; successful repayment awards Karma. The contract is the
///      only entity that links a stealth loan to a primary identity (for slashing),
///      and that link is kept in private storage rather than the public loan struct.
///
/// The contract is intentionally permissionless: anyone can request, fund, repay, or
/// mark default; the Karma oracle enforces sybil resistance and pricing.
contract BucketLending is ReentrancyGuard {
    // ---------------- CONFIG ----------------

    IKarma public immutable karma;

    /// @dev Fixed borrow denominations. Stored in ascending order.
    uint256[] public buckets;

    /// @dev How much ETH (in wei) of borrow capacity a single Karma point grants.
    uint256 public constant KARMA_BORROW_RATE = 0.05 ether;

    /// @dev Minimum Karma required to request a loan at all.
    uint256 public constant MIN_KARMA = 5;

    /// @dev Floor on interest after Karma discounts are applied (basis points).
    uint256 public constant MIN_INTEREST_BPS = 50; // 0.5%

    /// @dev Bps discount granted per Karma point, capped at the base rate.
    uint256 public constant INTEREST_DISCOUNT_BPS_PER_KARMA = 10; // 0.1% per Karma

    /// @dev Reputation awarded for a clean repayment.
    uint256 public constant KARMA_ON_REPAY = 3;

    /// @dev Reputation burned on default.
    uint256 public constant KARMA_ON_DEFAULT = 15;

    // ---------------- STATE ----------------

    enum Status {
        Open,
        Funded,
        Repaid,
        Defaulted,
        Cancelled
    }

    struct Loan {
        address borrowerStealth;
        uint256 bucketAmount;
        uint256 interestBps;
        uint256 duration;
        uint256 fundedAmount;
        uint256 fundedAt;
        uint256 dueTime;
        uint256 createdAt;
        Status status;
    }

    Loan[] private _loans;

    /// @dev Kept private so the public loan listing cannot be used to correlate
    ///      a stealth address with its primary identity. Only the contract itself
    ///      reads this, and only to slash/award Karma.
    mapping(uint256 => address) private _borrowerIdentity;

    /// @dev Per-loan ledger of lenders and their contributions.
    mapping(uint256 => address[]) private _lenders;
    mapping(uint256 => mapping(address => uint256)) private _contribution;

    // ---------------- EVENTS ----------------

    event LoanRequested(
        uint256 indexed loanId,
        address indexed borrowerStealth,
        uint256 bucketAmount,
        uint256 interestBps,
        uint256 duration
    );
    event LoanFunded(uint256 indexed loanId, address indexed lender, uint256 amount, uint256 totalFunded);
    event LoanFullyFunded(uint256 indexed loanId, uint256 dueTime);
    event LoanRepaid(uint256 indexed loanId, uint256 totalRepaid);
    event LoanDefaulted(uint256 indexed loanId);
    event LoanCancelled(uint256 indexed loanId);
    event LenderPaidOut(uint256 indexed loanId, address indexed lender, uint256 amount);

    // ---------------- ERRORS ----------------

    error InvalidBucket();
    error InvalidDuration();
    error LowKarma();
    error ExceedsBorrowLimit();
    error InterestTooLow();
    error UnknownLoan();
    error WrongStatus();
    error NotBorrower();
    error NotRequester();
    error InsufficientRepayment();
    error NotOverdue();
    error NothingToSend();
    error TransferFailed();

    // ---------------- CONSTRUCTOR ----------------

    constructor(address karmaAddress, uint256[] memory initialBuckets) {
        karma = IKarma(karmaAddress);
        require(initialBuckets.length > 0, "no buckets");
        for (uint256 i = 0; i < initialBuckets.length; i++) {
            if (i > 0) require(initialBuckets[i] > initialBuckets[i - 1], "buckets unsorted");
            buckets.push(initialBuckets[i]);
        }
    }

    // ---------------- VIEWS ----------------

    function bucketsList() external view returns (uint256[] memory) {
        return buckets;
    }

    function maxBucket() public view returns (uint256) {
        return buckets[buckets.length - 1];
    }

    function isValidBucket(uint256 amount) public view returns (bool) {
        for (uint256 i = 0; i < buckets.length; i++) {
            if (buckets[i] == amount) return true;
        }
        return false;
    }

    function getMaxBorrow(uint256 karmaScore) public pure returns (uint256) {
        return karmaScore * KARMA_BORROW_RATE;
    }

    function getAdjustedInterestBps(uint256 baseBps, uint256 karmaScore) public pure returns (uint256) {
        uint256 discount = karmaScore * INTEREST_DISCOUNT_BPS_PER_KARMA;
        if (discount >= baseBps) return MIN_INTEREST_BPS;
        uint256 adjusted = baseBps - discount;
        return adjusted < MIN_INTEREST_BPS ? MIN_INTEREST_BPS : adjusted;
    }

    function loansCount() external view returns (uint256) {
        return _loans.length;
    }

    function getLoan(uint256 loanId) external view returns (Loan memory) {
        if (loanId >= _loans.length) revert UnknownLoan();
        return _loans[loanId];
    }

    function getLoans() external view returns (Loan[] memory) {
        return _loans;
    }

    function getLenders(uint256 loanId) external view returns (address[] memory lenders, uint256[] memory amounts) {
        if (loanId >= _loans.length) revert UnknownLoan();
        address[] storage list = _lenders[loanId];
        lenders = list;
        amounts = new uint256[](list.length);
        for (uint256 i = 0; i < list.length; i++) {
            amounts[i] = _contribution[loanId][list[i]];
        }
    }

    function totalOwed(uint256 loanId) public view returns (uint256) {
        Loan storage l = _loans[loanId];
        return l.bucketAmount + (l.bucketAmount * l.interestBps) / 10_000;
    }

    // ---------------- CORE ----------------

    /// @notice Open a new loan request against a stealth address.
    /// @dev The caller is the primary identity. Their Karma gates the loan and will be
    ///      slashed on default / awarded on repayment. Only this contract knows the link.
    function requestLoan(
        address stealth,
        uint256 bucketAmount,
        uint256 baseInterestBps,
        uint256 duration
    ) external returns (uint256 loanId) {
        if (!isValidBucket(bucketAmount)) revert InvalidBucket();
        if (duration < 1 hours || duration > 365 days) revert InvalidDuration();
        if (baseInterestBps < MIN_INTEREST_BPS) revert InterestTooLow();

        uint256 karmaScore = karma.getKarma(msg.sender);
        if (karmaScore < MIN_KARMA) revert LowKarma();
        if (bucketAmount > getMaxBorrow(karmaScore)) revert ExceedsBorrowLimit();

        uint256 adjustedBps = getAdjustedInterestBps(baseInterestBps, karmaScore);

        loanId = _loans.length;
        _loans.push(
            Loan({
                borrowerStealth: stealth,
                bucketAmount: bucketAmount,
                interestBps: adjustedBps,
                duration: duration,
                fundedAmount: 0,
                fundedAt: 0,
                dueTime: 0,
                createdAt: block.timestamp,
                status: Status.Open
            })
        );
        _borrowerIdentity[loanId] = msg.sender;

        emit LoanRequested(loanId, stealth, bucketAmount, adjustedBps, duration);
    }

    /// @notice Contribute ETH to an open loan. When the target is hit the loan funds
    ///         and the bucket is forwarded to the stealth borrower. Overpayment is
    ///         refunded to the caller on the spot.
    function fundLoan(uint256 loanId) external payable nonReentrant {
        if (loanId >= _loans.length) revert UnknownLoan();
        Loan storage loan = _loans[loanId];
        if (loan.status != Status.Open) revert WrongStatus();
        if (msg.value == 0) revert NothingToSend();

        uint256 remaining = loan.bucketAmount - loan.fundedAmount;
        uint256 accepted = msg.value > remaining ? remaining : msg.value;
        uint256 refund = msg.value - accepted;

        if (_contribution[loanId][msg.sender] == 0) {
            _lenders[loanId].push(msg.sender);
        }
        _contribution[loanId][msg.sender] += accepted;
        loan.fundedAmount += accepted;

        emit LoanFunded(loanId, msg.sender, accepted, loan.fundedAmount);

        if (loan.fundedAmount == loan.bucketAmount) {
            loan.status = Status.Funded;
            loan.fundedAt = block.timestamp;
            loan.dueTime = block.timestamp + loan.duration;
            emit LoanFullyFunded(loanId, loan.dueTime);
            _send(loan.borrowerStealth, loan.bucketAmount);
        }

        if (refund > 0) _send(msg.sender, refund);
    }

    /// @notice Repay the outstanding principal + interest. Must be called from the
    ///         stealth address of record, not from the borrower's primary identity.
    function repayLoan(uint256 loanId) external payable nonReentrant {
        if (loanId >= _loans.length) revert UnknownLoan();
        Loan storage loan = _loans[loanId];
        if (loan.status != Status.Funded) revert WrongStatus();
        if (msg.sender != loan.borrowerStealth) revert NotBorrower();

        uint256 owed = totalOwed(loanId);
        if (msg.value < owed) revert InsufficientRepayment();

        loan.status = Status.Repaid;

        _distributeToLenders(loanId, owed);

        if (msg.value > owed) _send(msg.sender, msg.value - owed);

        address identity = _borrowerIdentity[loanId];
        if (identity != address(0)) {
            try karma.award(identity, KARMA_ON_REPAY, "repay") {} catch {}
        }

        emit LoanRepaid(loanId, owed);
    }

    /// @notice Flag an overdue loan as defaulted. Anyone may call. The stealth borrower
    ///         keeps the principal they received, but the primary identity tied to the
    ///         request is slashed on Karma. Lenders realize the loss.
    function markDefault(uint256 loanId) external {
        if (loanId >= _loans.length) revert UnknownLoan();
        Loan storage loan = _loans[loanId];
        if (loan.status != Status.Funded) revert WrongStatus();
        if (block.timestamp <= loan.dueTime) revert NotOverdue();

        loan.status = Status.Defaulted;

        address identity = _borrowerIdentity[loanId];
        if (identity != address(0)) {
            try karma.slash(identity, KARMA_ON_DEFAULT, "default") {} catch {}
        }

        emit LoanDefaulted(loanId);
    }

    /// @notice The original requester can cancel an Open loan at any time; any
    ///         lenders who already contributed are refunded.
    function cancelLoan(uint256 loanId) external nonReentrant {
        if (loanId >= _loans.length) revert UnknownLoan();
        Loan storage loan = _loans[loanId];
        if (loan.status != Status.Open) revert WrongStatus();
        if (msg.sender != _borrowerIdentity[loanId]) revert NotRequester();

        loan.status = Status.Cancelled;

        address[] storage lenderList = _lenders[loanId];
        for (uint256 i = 0; i < lenderList.length; i++) {
            address lender = lenderList[i];
            uint256 amount = _contribution[loanId][lender];
            if (amount > 0) {
                _contribution[loanId][lender] = 0;
                _send(lender, amount);
                emit LenderPaidOut(loanId, lender, amount);
            }
        }

        emit LoanCancelled(loanId);
    }

    // ---------------- INTERNAL ----------------

    function _distributeToLenders(uint256 loanId, uint256 repaidTotal) internal {
        Loan storage loan = _loans[loanId];
        address[] storage lenderList = _lenders[loanId];
        uint256 principal = loan.bucketAmount;

        uint256 paid;
        for (uint256 i = 0; i < lenderList.length; i++) {
            address lender = lenderList[i];
            uint256 share = _contribution[loanId][lender];
            if (share == 0) continue;

            uint256 amount = i == lenderList.length - 1
                ? repaidTotal - paid // absorb rounding dust in the last payout
                : (repaidTotal * share) / principal;
            paid += amount;
            _contribution[loanId][lender] = 0;
            _send(lender, amount);
            emit LenderPaidOut(loanId, lender, amount);
        }
    }

    function _send(address to, uint256 amount) internal {
        (bool ok, ) = payable(to).call{ value: amount }("");
        if (!ok) revert TransferFailed();
    }
}

