// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title MockKarma
/// @notice Local stand-in for Status Network's non-transferable Karma reputation primitive.
///         Exposes the same `getKarma(address)` read surface we rely on in production,
///         plus privileged `award`/`slash` hooks for authorized modules (e.g. BucketLending)
///         and a small demo faucet so hackathon users can bootstrap a reputation.
contract MockKarma {
    address public owner;

    mapping(address => uint256) private _karma;
    mapping(address => bool) public authorizedModule;

    uint256 public constant FAUCET_MAX_PER_CALL = 25;

    event KarmaChanged(address indexed user, uint256 newKarma, int256 delta, string reason);
    event ModuleAuthorized(address indexed module, bool authorized);

    error NotOwner();
    error NotAuthorized();
    error FaucetTooLarge();

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    modifier onlyAuthorized() {
        if (!authorizedModule[msg.sender] && msg.sender != owner) revert NotAuthorized();
        _;
    }

    constructor() {
        owner = msg.sender;
        authorizedModule[msg.sender] = true;
        emit ModuleAuthorized(msg.sender, true);
    }

    function setAuthorizedModule(address module, bool ok) external onlyOwner {
        authorizedModule[module] = ok;
        emit ModuleAuthorized(module, ok);
    }

    function getKarma(address user) external view returns (uint256) {
        return _karma[user];
    }

    function award(address user, uint256 amount, string calldata reason) external onlyAuthorized {
        _karma[user] += amount;
        emit KarmaChanged(user, _karma[user], int256(amount), reason);
    }

    function slash(address user, uint256 amount, string calldata reason) external onlyAuthorized {
        uint256 current = _karma[user];
        uint256 next = amount > current ? 0 : current - amount;
        _karma[user] = next;
        emit KarmaChanged(user, next, -int256(amount), reason);
    }

    /// @notice Self-serve faucet for demos. Capped per-call so nobody can instantly farm reputation.
    function faucet(uint256 amount) external {
        if (amount == 0 || amount > FAUCET_MAX_PER_CALL) revert FaucetTooLarge();
        _karma[msg.sender] += amount;
        emit KarmaChanged(msg.sender, _karma[msg.sender], int256(amount), "faucet");
    }
}
